from langchain_mcp_adapters.client import MultiServerMCPClient

client = MultiServerMCPClient({
    "ai-agent-passport": {
        "command": "python3",
        "args": ["/ABSOLUTE/PATH/TO/ai-agent-passport/mcp_server.py"],
        "transport": "stdio",
        "env": {
            "PASSPORT_API_URL": "https://ai-agent-passport.onrender.com",
            "BILLING_WEBHOOK_SECRET": "your-billing-webhook-secret-from-render-env"
        }
    }
})

tools = await client.get_tools()
# tools: register_agent, verify_agent_passport, refill_agent_credits
